// @n8n-evol-I:primitive — exempt from pure-function discipline
// Build the n8n-lock-<scope> + :meta key pair to GET-then-verify before deleting.
const scope = $json.scope || 'default';
const lockId = $json.lock_id || null;
const key = `n8n-lock-${scope}`;
const metaKey = `${key}:meta`;
return [{ json: { scope, key, meta_key: metaKey, provided_lock_id: lockId } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
// Three outcomes:
//   - GET miss   → lock already released (TTL or earlier release). Idempotent success.
//   - lock_id match → caller owns the lock. DEL counter + meta to release.
//   - lock_id mismatch → ownership violation. StopAndError so the caller learns
//     they're trying to release someone else's lock — usually a logic bug.
const ctx = $('Build Release Context').first().json;
const lockValue = $json.LOCK_META;
const providedLockId = ctx.provided_lock_id;

if (lockValue === null || lockValue === undefined || lockValue === '') {
  return [{
    json: {
      is_match: true,
      already_released: true,
      provided_lock_id: providedLockId,
      stored_lock_id: null,
      workflow_id: 'none',
      workflow_name: 'none (key absent)',
      execution_id: 'none',
      locked_at: 'none',
      scope: ctx.scope,
      key: ctx.key,
      meta_key: ctx.meta_key,
    },
  }];
}

let parsedLock;
try {
  parsedLock = JSON.parse(lockValue);
} catch (e) {
  // Legacy / corrupt meta — fall through as unknown identity, mark not-mine.
  parsedLock = { lock_id: String(lockValue), workflow_id: 'unknown', workflow_name: 'unknown (legacy meta)', execution_id: 'unknown', locked_at: 'unknown' };
}
if (parsedLock === null || typeof parsedLock !== 'object') {
  parsedLock = { lock_id: String(lockValue), workflow_id: 'unknown', workflow_name: 'unknown (legacy meta)', execution_id: 'unknown', locked_at: 'unknown' };
}

const isMatch = parsedLock.lock_id === providedLockId;
return [{
  json: {
    is_match: isMatch,
    already_released: false,
    provided_lock_id: providedLockId,
    stored_lock_id: parsedLock.lock_id,
    workflow_id: parsedLock.workflow_id,
    workflow_name: parsedLock.workflow_name,
    execution_id: parsedLock.execution_id || 'unknown',
    locked_at: parsedLock.locked_at,
    scope: ctx.scope,
    key: ctx.key,
    meta_key: ctx.meta_key,
  },
}];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Release Context').first().json;
const parsed = $('Parse + Verify Ownership').first().json;
return [{ json: { released: true, idempotent: parsed.already_released === true, scope: ctx.scope, lock_id: parsed.provided_lock_id } }];
